package com.example.sklepinternetowyprojekt.Controler;
import com.example.sklepinternetowyprojekt.Model.Item;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;

//alt+ctrl+o  ->usuwa nieużywane importy

@Controller
public class HomeController {

    static List<Item> items= new ArrayList<>();
    static {
        items.add(new Item("Koszulka RP",
                new BigDecimal("35.50"),
                "data:image/jpeg;base64,")
        );
        items.add(new Item("Koszulka FCB",
                new BigDecimal("35.50"),
                "data:image/jpeg;base64,")
                );
    items.add(new Item("Koszulka GKS",
                        new BigDecimal("35.50"),
                        "data:image/jpeg;base64,")
    );
    }



    @GetMapping("/")
    //@ResponseBody //-> tego sie używa by nasłuchiwać tego, co funkcja pod nią zwróci
    public String home(Model model){
        model.addAttribute("items",items);
    //new Item("Koszulka",new BigDecimal("35.50"),"data:image/jpeg;base64,"));
        return "home"; //sam sobie szuka pliku o tej nazwie w template (bez roszerzenia sie pisze)
        //return new Item("Koszulka",new BigDecimal("35.50"),"data:image/jpeg;base64,");
    }
}
